const _ = require("lodash");

class ProblemsService {
  constructor({ models }) {
    this.models = models;
  }

  async list({ limit, offset, difficulty, tags, includeComponents }) {
    // Fetch problems with filters
    const where = {};
    if (difficulty) {
      where.difficulty = difficulty;
    }
    if (tags && tags.length > 0) {
      where.tags = { $overlap: tags };
    }

    // Fetch problems with pagination
    const problems = await this.models.Problem.findAll({
      where,
      limit,
      offset
    });

    // Prepare response
    const response = {
      problems,
      metadata: {}
    };

    if (includeComponents) {
      // We need to compute language and status totals for the filtered and limited problems
      // Extract all components from the filtered problems
      const components = _.flatMap(problems, p => p.components || []);

      // Count by language
      const componentLanguageTotals = _.countBy(components, c => c.language);

      // Count by status
      const componentStatusTotals = _.countBy(components, c => c.status);

      response.metadata.componentLanguageTotals = componentLanguageTotals;
      response.metadata.componentStatusTotals = componentStatusTotals;
    }

    return response;
  }
}

module.exports = ProblemsService;
